import numpy as np
from collections import deque

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape

    merged = grid.copy()
    merged[merged == 7] = 4

    visited = np.zeros((H, W), dtype=bool)
    components = []

    def bfs(r0, c0):
        q = deque([(r0, c0)])
        visited[r0, c0] = True
        cells = []
        while q:
            r, c = q.popleft()
            cells.append((r, c))
            for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W and not visited[nr, nc] and merged[nr, nc] == 4:
                    visited[nr, nc] = True
                    q.append((nr, nc))
        return cells

    for r in range(H):
        for c in range(W):
            if not visited[r, c] and merged[r, c] == 4:
                components.append(set(map(tuple, bfs(r, c))))

    seven_cells = set(zip(*np.where(grid == 7)))

    main_comps = []
    minor_comps = []
    for comp in components:
        if comp & seven_cells:
            main_comps.append(comp)
        else:
            minor_comps.append(comp)

    main_comps.sort(key=len, reverse=True)
    comp_a_cells = main_comps[0]
    comp_b_cells = set()
    for mc in main_comps[1:]:
        comp_b_cells |= mc

    def bbox(cells):
        rs = [r for r,c in cells]
        cs = [c for r,c in cells]
        return min(rs), max(rs), min(cs), max(cs)

    a_bbox = bbox(comp_a_cells)
    b_bbox = bbox(comp_b_cells) if comp_b_cells else None

    for mc in minor_comps:
        sample_r, sample_c = next(iter(mc))
        in_a = (a_bbox[0] <= sample_r <= a_bbox[1] and a_bbox[2] <= sample_c <= a_bbox[3])
        in_b = b_bbox and (b_bbox[0] <= sample_r <= b_bbox[1] and b_bbox[2] <= sample_c <= b_bbox[3])

        if in_a and not in_b:
            comp_a_cells = comp_a_cells | mc
        elif in_b and not in_a:
            comp_b_cells = comp_b_cells | mc
        else:
            min_dist_a = min(abs(sample_r - r) + abs(sample_c - c) for r, c in comp_a_cells)
            min_dist_b = min(abs(sample_r - r) + abs(sample_c - c) for r, c in comp_b_cells) if comp_b_cells else float('inf')
            if min_dist_a <= min_dist_b:
                comp_a_cells = comp_a_cells | mc
            else:
                comp_b_cells = comp_b_cells | mc

    a_7s = seven_cells & comp_a_cells
    b_7s = seven_cells & comp_b_cells
    a_4s = comp_a_cells - seven_cells
    b_4s = comp_b_cells - seven_cells

    valid_offsets = []
    if a_7s and b_7s:
        ra7, ca7 = next(iter(a_7s))
        for rb4, cb4 in b_4s:
            dr = ra7 - rb4
            dc = ca7 - cb4

            ok = True
            for ra, ca in a_7s:
                if (ra - dr, ca - dc) not in b_4s:
                    ok = False
                    break
            if not ok:
                continue

            for rb, cb in b_7s:
                if (rb + dr, cb + dc) not in a_4s:
                    ok = False
                    break
            if not ok:
                continue

            valid_offsets.append((dr, dc))

    if len(valid_offsets) == 1:
        dr, dc = valid_offsets[0]
    else:
        best_offset = None
        best_total = float('inf')
        for dr_c, dc_c in valid_offsets:
            b_shifted_7s = [(r + dr_c, c + dc_c) for r, c in b_7s]
            total = 0
            for ra, ca in a_7s:
                total += min(abs(ra - rb) + abs(ca - cb) for rb, cb in b_shifted_7s)
            for rb, cb in b_shifted_7s:
                total += min(abs(ra - rb) + abs(ca - cb) for ra, ca in a_7s)
            if total < best_total:
                best_total = total
                best_offset = (dr_c, dc_c)
        dr, dc = best_offset

    b_shifted = set((r + dr, c + dc) for r, c in comp_b_cells)

    all_cells = comp_a_cells | b_shifted
    min_r = min(r for r, c in all_cells)
    max_r = max(r for r, c in all_cells)
    min_c = min(c for r, c in all_cells)
    max_c = max(c for r, c in all_cells)

    out_h = max_r - min_r + 1
    out_w = max_c - min_c + 1
    output = [[1] * out_w for _ in range(out_h)]

    for r, c in comp_a_cells:
        output[r - min_r][c - min_c] = 4
    for r, c in b_shifted:
        output[r - min_r][c - min_c] = 4

    return output

